43: // NewStructuredMergeManager creates a new Manager that merges apply requests
44: // and update managed fields for other types of requests.
45: func NewStructuredMergeManager(typeConverter TypeConverter, objectConverter runtime.ObjectConvertor, objectDefaulter runtime.ObjectDefaulter, gv schema.GroupVersion, hub schema.GroupVersion, resetFields map[fieldpath.APIVersion]fieldpath.Filter) (Manager, error) {
46: 	if typeConverter == nil {
47: 		return nil, fmt.Errorf("typeconverter must not be nil")
48: 	}
49: 	return &structuredMergeManager{
50: 		typeConverter:   typeConverter,
51: 		objectConverter: objectConverter,
52: 		objectDefaulter: objectDefaulter,
53: 		groupVersion:    gv,
54: 		hubVersion:      hub,
55: 		updater: merge.Updater{
56: 			Converter:    newVersionConverter(typeConverter, objectConverter, hub), // This is the converter provided to SMD from k8s
57: 			IgnoreFilter: resetFields,
58: 		},
59: 	}, nil
60: }
