90: // Update implements Manager.
91: func (f *structuredMergeManager) Update(liveObj, newObj runtime.Object, managed Managed, manager string) (runtime.Object, Managed, error) {
92: 	newObjVersioned, err := f.toVersioned(newObj)
93: 	if err != nil {
94: 		return nil, nil, fmt.Errorf("failed to convert new object (%v) to proper version (%v): %v", objectGVKNN(newObj), f.groupVersion, err)
95: 	}
96: 	liveObjVersioned, err := f.toVersioned(liveObj)
97: 	if err != nil {
98: 		return nil, nil, fmt.Errorf("failed to convert live object (%v) to proper version: %v", objectGVKNN(liveObj), err)
99: 	}
100: 	newObjTyped, err := f.typeConverter.ObjectToTyped(newObjVersioned, typed.AllowDuplicates)
101: 	if err != nil {
102: 		return nil, nil, fmt.Errorf("failed to convert new object (%v) to smd typed: %v", objectGVKNN(newObjVersioned), err)
103: 	}
104: 	liveObjTyped, err := f.typeConverter.ObjectToTyped(liveObjVersioned, typed.AllowDuplicates)
105: 	if err != nil {
106: 		return nil, nil, fmt.Errorf("failed to convert live object (%v) to smd typed: %v", objectGVKNN(liveObjVersioned), err)
107: 	}
108: 	apiVersion := fieldpath.APIVersion(f.groupVersion.String())
109: 
110: 	// TODO(apelisse) use the first return value when unions are implemented
111: 	_, managedFields, err := f.updater.Update(liveObjTyped, newObjTyped, apiVersion, managed.Fields(), manager)
112: 	if err != nil {
113: 		return nil, nil, fmt.Errorf("failed to update ManagedFields (%v): %v", objectGVKNN(newObjVersioned), err)
114: 	}
115: 	managed = NewManaged(managedFields, managed.Times())
116: 
117: 	return newObj, managed, nil
118: }
