184: func (f *structuredMergeManager) toVersioned(obj runtime.Object) (runtime.Object, error) {
185: 	return f.objectConverter.ConvertToVersion(obj, f.groupVersion)
186: }
187: 
188: func (f *structuredMergeManager) toUnversioned(obj runtime.Object) (runtime.Object, error) {
189: 	return f.objectConverter.ConvertToVersion(obj, f.hubVersion)
190: }
