226: func encodeManagerVersionedSet(manager string, versionedSet fieldpath.VersionedSet) (encodedVersionedSet *metav1.ManagedFieldsEntry, err error) {
227: 	encodedVersionedSet = &metav1.ManagedFieldsEntry{}
